blocks.body:
{
    "level": "A1–A2",
    "intro": "W tym temacie poznasz <strong>przymiotniki dzierżawcze i zaimki dzierżawcze</strong> – dwie formy wyrażania przynależności.",
    "rules": [
        {
            "label": "Przymiotniki",
            "color": "emerald",
            "text": "<strong>Przymiotniki dzierżawcze</strong> – przed noun:",
            "example": "To jest moja książka. Ma na imię Maria."
        },
        {
            "label": "Zaimki",
            "color": "blue",
            "text": "<strong>Zaimki dzierżawcze</strong> — zamiast rzeczownika:",
            "example": "Ta książka jest moja. Niebieska torba jest jej."
        },
        {
            "label": "Kluczowa zasada",
            "color": "amber",
            "text": "<strong>Reguła:</strong> przymiotnik + rzeczownik, zaimek zamiast rzeczownika",
            "example": "mój samochód (adj+noun) → Samochód jest mój (zaimek)"
        }
    ]
}

{
    "title": "1. Dwie formy dzierżawcze",
    "intro": "Aby wyrazić przynależność (czyj to jest?), język angielski ma dwie formy:",
    "items": [
        {
            "label": "Przymiotniki",
            "title": "Przymiotniki dzierżawcze",
            "subtitle": "my, your, his, her, it, our, ich — stoją PRZED rzeczownik"
        },
        {
            "label": "Zaimki",
            "title": "Zaimki dzierżawcze",
            "subtitle": "moje, twoje, jego, jej, nasze, ich — stoją ZAMIAST rzeczownika "
        }
    ]
}

{
    "title": "2. Pełna tabela form dzierżawczych",
    "intro": "Porównanie wszystkich przymiotników dzierżawczych i zaimków dzierżawczych:",
    "rows": [
        {
            "en": "my",
            "ua": "moje/moje/moje (+ rzeczownik)",
            "note": "moje - moje (niezależne)"
        },
        {
            "en": "twoje",
            "ua": "twoje (+ rzeczownik)",
            "note": "twoje - twoje (niezależne)"
        },
        {
            "en": "jego[[[CODX_5]]]jego (+ rzeczownik)[[CODX_6]]]jego jego (niezależnie)",
            "ua": "його (+ noun)",
            "note": "his — його (самостійно)"
        },
        {
            "en": "jej",
            "ua": "jej (+ rzeczownik)",
            "note": "jej - jej (niezależnie)"
        },
        {
            "en": "jego[[CODX_SEG_11]]]jego/niej zwierzęta/obiekty",
            "ua": "його/її для тварин/предметів",
            "note": " NIE ma zaimka w formie!"
        },
        {
            "en": "nasz",
            "ua": "nasz (+ rzeczownik)",
            "note": "nasz - nasz (niezależny)"
        },
        {
            "en": "ich",
            "ua": "ich (+ rzeczownik)",
            "note": "ich (niezależnie)"
        }
    ],
    "warning": "📌 Jego ma tę samą formę przymiotnika i zaimka. NIE ma formy zaimkowej!"
}

{
    "title": "3. Przymiotniki dzierżawcze – przymiotniki dzierżawcze",
    "sections": [
        {
            "label": "Co to są przymiotniki dzierżawcze?",
            "color": "emerald",
            "description": "Przymiotniki dzierżawcze <strong>zawsze występują przed rzeczownikiem</strong> i wskazują, kto jest właścicielem czegoś. NIE mogą stać samodzielnie.",
            "examples": [
                {
                    "en": "To jest moja książka.",
                    "ua": "To jest moja książka."
                },
                {
                    "en": "Twój samochód jest nowy.",
                    "ua": "Twój samochód jest nowy."
                },
                {
                    "en": "Jego imię to John.",
                    "ua": "Ma na imię John."
                },
                {
                    "en": "Jej siostra tu mieszka.",
                    "ua": "Jej siostra tu mieszka."
                },
                {
                    "en": "Pies machał ogonem.",
                    "ua": "Pies machał ogonem ogon."
                },
                {
                    "en": "Nasz dom jest duży.",
                    "ua": "Nasz dom jest duży."
                },
                {
                    "en": "Ich dzieci są w szkole.",
                    "ua": "Ich dzieci są w szkole."
                }
            ]
        },
        {
            "label": "Zawsze przed rzeczownikiem",
            "color": "sky",
            "description": "Przymiotniki dzierżawcze <strong>nigdy nie występują osobno</strong> — zawsze następuje po nich rzeczownik.",
            "examples": [
                {
                    "en": "mój przyjaciel (✓)",
                    "ua": "mój przyjaciel"
                },
                {
                    "en": "To jest moje. (✗)",
                    "ua": "BŁĄD - brak rzeczownika!"
                },
                {
                    "en": "jej pomysł (✓)",
                    "ua": "jej pomysł"
                },
                {
                    "en": "Pomysł to ona. (✗)",
                    "ua": "BŁĄD - wymagany jest zaimek jej!"
                }
            ],
            "note": "📌 Przymiotnik zawsze + rzeczownik. Nie działa bez rzeczownika!"
        },
        {
            "label": "Mój, twój, jego, jej, jego, nasz, ich",
            "color": "purple",
            "description": "Wszystkie siedem przymiotników dzierżawczych jest używanych w ten sam sposób – przed rzeczownikiem.",
            "examples": [
                {
                    "en": "mój długopis, twoja torba, jego telefon",
                    "ua": "mój długopis, twoja torba, jego telefon"
                },
                {
                    "en": "jej laptop, jego kolor, nasz plan",
                    "ua": "jej laptop, jego kolor, nasz plan"
                },
                {
                    "en": "jej dom",
                    "ua": "ich dom"
                }
            ]
        },
        {
            "label": "Twoje kontra to – nie rób tego mylić!",
            "color": "amber",
            "description": "<strong>Its</strong> (bez apostrofu) jest przymiotnikiem dzierżawczym. <strong>To</strong> (z apostrofem) to skrót od tego.",
            "examples": [
                {
                    "en": "Kot zjadł swoje jedzenie. (zaborczy)",
                    "ua": "Kot zjadł swoje jedzenie."
                },
                {
                    "en": "Pada deszcz. (jest)",
                    "ua": "Pada deszcz."
                },
                {
                    "en": "Miasto i jego mieszkańcy. (zaborczy)",
                    "ua": "Miasto i jego ludzie."
                },
                {
                    "en": "To piękny dzień. (jest)",
                    "ua": "Dzień dobry."
                }
            ],
            "note": "📌 Jego = zaborczy (czyj). To = to jest (jest)."
        }
    ]
}

{
    "title": "4. Zaimki dzierżawcze — Zaimki dzierżawcze",
    "sections": [
        {
            "label": "Co to są zaimki dzierżawcze?",
            "color": "blue",
            "description": "Zaimki dzierżawcze <strong>zastępują rzeczownik</strong> i pokazują własność. Stoją osobno, BEZ rzeczownika po nich.",
            "examples": [
                {
                    "en": "Ta książka jest moja.",
                    "ua": "Ta książka jest moja."
                },
                {
                    "en": "Samochód jest Twój.",
                    "ua": "Машина твой."
                },
                {
                    "en": "Ten długopis jest jego.",
                    "ua": "Ten długopis jest jego."
                },
                {
                    "en": "Niebieska torba jest jej.",
                    "ua": "Niebieska torba jest jej."
                },
                {
                    "en": "Dom jest nasz.",
                    "ua": "Dom jest nasze."
                },
                {
                    "en": "Te klucze są ich.",
                    "ua": "Te klucze są ich."
                }
            ]
        },
        {
            "label": "samodzielne",
            "color": "sky",
            "description": "Zaimki dzierżawcze <strong>nie potrzebują rzeczownika</strong> po sobie – same w sobie zastępują rzeczownik.",
            "examples": [
                {
                    "en": "To jest moje. (✓)",
                    "ua": "To jest moja książka."
                },
                {
                    "en": "To jest moja książka. (✗)",
                    "ua": "BŁĄD – zbędny rzeczownik!"
                },
                {
                    "en": "To jest jej. (✓)",
                    "ua": "To jest jej."
                },
                {
                    "en": "To jest jej torba. (✗)",
                    "ua": "BŁĄD - nie można użyć z rzeczownikiem!"
                }
            ],
            "note": "📌 Zaimek zamiast rzeczownika. Nigdy nie dodawaj rzeczownika po!"
        },
        {
            "label": "Mój, twój, jego, jej, nasz, ich",
            "color": "purple",
            "description": "Sześć zaimków dzierżawczych (nie ma tej formy!).",
            "examples": [
                {
                    "en": "Czy to pióro jest Twoje? — Tak, jest mój.",
                    "ua": "Czy to twój długopis? — Tak, mój."
                },
                {
                    "en": "Jego samochód jest czerwony, jej niebieski.",
                    "ua": "Jego samochód jest czerwony, jej niebieski."
                },
                {
                    "en": "Nasze biuro jest duże, ich jest małe.",
                    "ua": "Nasze biuro jest duże, a ich małe."
                }
            ]
        },
        {
            "label": "To jego szczególny przypadek",
            "color": "amber",
            "description": "<strong>Jego</strong> ma tę samą formę co przymiotnik dzierżawczy i zaimek dzierżawczy.",
            "examples": [
                {
                    "en": "jego książka (przymiotnik)",
                    "ua": "jego książka"
                },
                {
                    "en": "To książka jest jego. (zaimek)",
                    "ua": "Ta książka jest jego."
                }
            ],
            "note": "📌 Jego to jedyne słowo, które działa w obie strony!"
        }
    ]
}

{
    "title": "5. Jak wybrać: przymiotnik czy zaimek?",
    "sections": [
        {
            "label": "Zasada 1: Czy po formie dzierżawczej występuje rzeczownik?",
            "color": "emerald",
            "description": "Jeśli po formie dzierżawczej występuje <strong>rzeczownik</strong>, użyj <strong>przymiotnika</strong>.",
            "examples": [
                {
                    "en": "To jest mój samochód.",
                    "ua": "To jest mój samochód. (to rzeczownik „samochód”)"
                },
                {
                    "en": "Jej siostra jest wysoka.",
                    "ua": "Jej siostra jest wysoka. (jest rzeczownikiem „siostra”)"
                },
                {
                    "en": "Ich dom jest piękny.",
                    "ua": "Ich dom jest piękny. (jest rzeczownik „dom”)"
                }
            ]
        },
        {
            "label": "Zasada 2: Czy rzeczownik został już wspomniany?",
            "color": "blue",
            "description": "Jeśli rzeczownik jest już znany i nie chcesz go powtarzać, użyj <strong>zaimka</strong>.",
            "examples": [
                {
                    "en": "Mój samochód jest czerwony. Twój jest niebieski.",
                    "ua": "Mój samochód jest czerwony. Twoja niebieska (samochód się nie powtórzył)"
                },
                {
                    "en": "Jej torba jest duża. Moja jest mała.",
                    "ua": "Jej torba jest duża. Mój mały. (torba się nie powtórzyła)"
                },
                {
                    "en": "Ich biuro jest nowe. Nasze jest stare.",
                    "ua": "Ich biuro jest nowe. Nasz stary."
                }
            ]
        },
        {
            "label": "Zasada 3: Pytanie „Czyje?” — Jest moja.",
            "color": "purple",
            "description": "У відповіді на питання <strong>Whose?</strong> (Чий?) часто використовуємо pronoun.",
            "examples": [
                {
                    "en": "Whose book is this? — It's mine.",
                    "ua": "Czyja to książka? - Kopalnia."
                },
                {
                    "en": "Czyje to klucze? — Są jej.",
                    "ua": "Czyje to klucze? — Jej."
                },
                {
                    "en": "Czyj to samochód? — Jest ich.",
                    "ua": "Czyj to samochód? — Ich."
                }
            ],
            "note": "📌 W odpowiedzi: moje/twoje/jego/jej/nasze/ich (zaimki)."
        }
    ]
}

{
    "title": "6. Porównanie formularzy",
    "sections": [
        {
            "label": "Moje vs Moje",
            "color": "emerald",
            "description": "<strong>Moje</strong> + rzeczownik. <strong>Moja</strong> zamiast rzeczownika.",
            "examples": [
                {
                    "en": "To jest moja książka.",
                    "ua": "To jest moja książka. (moja + książka)"
                },
                {
                    "en": "Ta książka jest moja.",
                    "ua": "Ta książka jest moja. (mój zamiast książki)"
                },
                {
                    "en": "Mój telefon jest nowy.",
                    "ua": "Mój telefon jest nowy."
                },
                {
                    "en": "Nowy telefon jest mój.",
                    "ua": "Mój nowy telefon."
                }
            ]
        },
        {
            "label": "Twoje vs Twój",
            "color": "sky",
            "description": "<strong>Twój</strong> + rzeczownik. <strong>Twój</strong> zamiast rzeczownika.",
            "examples": [
                {
                    "en": "Czy to Twój samochód?",
                    "ua": "Czy to Twój samochód? (Twój + samochód)"
                },
                {
                    "en": "Czy ten samochód jest Twój?",
                    "ua": "Czy ten samochód jest Twój? (twój zamiast samochodu)"
                },
                {
                    "en": "Twój pomysł jest świetny.",
                    "ua": "Twój pomysł jest świetny."
                },
                {
                    "en": "Pomysł jest Twój.",
                    "ua": "Twój pomysł."
                }
            ]
        },
        {
            "label": "Jej vs Jej",
            "color": "purple",
            "description": "<strong>Jej</strong> + rzeczownik. <strong>Jej</strong> zamiast rzeczownika.",
            "examples": [
                {
                    "en": "Jej torba jest niebieska.",
                    "ua": "Jej torba jest niebieska. (ona + torba)"
                },
                {
                    "en": "Niebieska torba jest jej.",
                    "ua": "Niebieska torba jest jej. (jej zamiast torby)"
                },
                {
                    "en": "Jej odpowiedź jest poprawna.",
                    "ua": "Jej odpowiedź jest poprawna."
                },
                {
                    "en": "Prawidłowa odpowiedź to jej.",
                    "ua": "Prawidłowa odpowiedź to jej."
                }
            ]
        },
        {
            "label": "Nasi kontra nasi, ich kontra Ich",
            "color": "amber",
            "description": "Ta sama zasada dotyczy naszych/naszych i ich/ich.",
            "examples": [
                {
                    "en": "Our house vs The house is ours",
                    "ua": "Наш будинок vs Будинок наш"
                },
                {
                    "en": "Their dog vs The dog is theirs",
                    "ua": "Їхня собака vs Собака їхня"
                }
            ],
            "note": "📌 Adjective + noun. Pronoun замість noun."
        }
    ]
}

{
    "title": "7. Typowe błędy osób mówiących po ukraińsku",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Zaimek + rzeczownik (dodatkowy rzeczownik).",
            "wrong": "To jest moja książka. / To jej samochód.",
            "right": " ✅ <span class="font-mono">To jest moja książka. / To jej samochód.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Przymiotnik bez rzeczownika.",
            "wrong": "Ta książka jest moja. / Ten samochód to ona.",
            "right": "​​​​ <span class="font-mono">Ta książka jest moja. / Samochód jest jej.</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Pomieszanie jego i jego.",
            "wrong": "Paduje deszcz. / Pies machał ogonem.",
            "right": " ✅ <span class="font-mono">Pada deszcz. / Pies machał ogonem.</span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Niepoprawna forma (miny, jej książka).",
            "wrong": "To jest moje. / To jej torba.",
            "right": " ✅ <span class="font-mono">To jest moja. / To jej torba.</span>"
        }
    ]
}

{
    "title": "9. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz właściwą formę",
    "select_intro": "Wpisz w puste miejsca właściwą formę dzierżawczą (przymiotnik lub zaimek).",
    "selects": [
        {
            "label": "To jest ___ książka. (moje / moje)",
            "prompt": "Jaka forma?"
        },
        {
            "label": "Ta książka jest ___. (mój / mój)",
            "prompt": "Jaki kształt?"
        },
        {
            "label": "___ samochód jest czerwony. (Jej / Jej)",
            "prompt": "Jaki kształt?"
        },
        {
            "label": "Czerwony samochód to ___. (ona/jej)",
            "prompt": "Jaki kształt?"
        },
        {
            "label": "Czy to długopis ___? (twój/twój)",
            "prompt": "Który formularz?"
        }
    ],
    "options": [
        "moja",
        "moja",
        "twoja",
        "twoja",
        "jego",
        "jej ",
        "jej",
        "nasz[[CODX_SEG_24]]]nasz",
        "ours",
        "jej",
        "ich"
    ],
    "input_title": "Ćwiczenie 2. Wypełnij puste miejsca",
    "input_intro": "Wpisz poprawną formę dzierżawczą.",
    "inputs": [
        {
            "before": "To jest ___ telefon. (mój telefon)",
            "after": " →"
        },
        {
            "before": "Ten telefon to ___. (mój)",
            "after": "→"
        },
        {
            "before": "___ dom jest duży. (nasz dom)",
            "after": " →"
        },
        {
            "before": "Dom jest ___. (nasz)",
            "after": "→"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Korekcja błędów",
    "rephrase_intro": "Znajdź i popraw błąd za pomocą form dzierżawczych.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "To jest moja książka.",
            "example_target": "To jest moja książka."
        },
        {
            "original": "1. Ta książka jest moja.",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "2. To jej samochód.",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "3. To piękny dzień. — mój / mój, twój / twój (bieżący)",
            "placeholder": "Виправ помилку"
        }
    ]
}

{
    "title": "Інші сторінки з категорії Займенники та вказівні слова",
    "items": [
        {
            "label": "Pronouns — Займенники (огляд)",
            "current": false
        },
        {
            "label": "Personal & Object Pronouns — Особові й об'єктні",
            "current": false
        },
        {
            "label": "Possessive Adjectives vs Pronouns — my / mine, your / yours (поточна)",
            "current": true
        },
        {
            "label": "Zaimki zwrotne — Zaimki zwrotne",
            "current": false
        }
    ]
}
